sys_script_include.script:
var task_privacy = Class.create();
task_privacy.prototype = {
    initialize: function() {
		this.userInfo = new UserInfoScripts();
    },

	userCanAccessOU: function(officeId){
		var currentUserId = gs.getUserID();
		var isUserInGroup = false;
		var isOpenOrg = false;
		var organizationalPrivacy;
		var userCanReadOU = false;

		organizationalPrivacy = this.getTopOUOrganizationalPrivacy(officeId);
		isOpenOrg = organizationalPrivacy == 'open';
		var isUserTaskerApplicationAdmin = this.userInfo.UserHasRole('x_153465_discovert.tasker_application_admin');
		if(isOpenOrg || isUserTaskerApplicationAdmin){
			userCanReadOU=true;
		} else {
			isUserInGroup = this.isUserInOrgStructure(officeId,currentUserId);
			if(isUserInGroup){
				userCanReadOU = true;
			}
		}
		return userCanReadOU;
	},

	getTopOUOrganizationalPrivacy: function(ouID){
		var organizationalPrivacy = "open";
		// DFCT0011800 - this is used to determine permissions, using GlideRecord Secure causes an ACL Loop

		var grOfficeOU = new GlideRecord("x_153465_discovert_discover_office_hierarchy");
		if(grOfficeOU.get(ouID)){
			// now get Top OU
			topOUId = grOfficeOU.getValue("u_top_ou");
			// DFCT0011800 - this is used to determine permissions, using GlideRecord Secure causes an ACL Loop
			var grTopOU = new GlideRecord("x_153465_discovert_discover_office_hierarchy");
			if(grTopOU.get(topOUId)){
				organizationalPrivacy = grTopOU.getValue("u_organizational_privacy");
			}
		}
		return organizationalPrivacy;
	},

	// NOTE: this should move into UserInfo or Oganizational Scripts after initial release
	isUserInOrgStructure: function (ouID, userID){
		var answer = false;
		// get the top ID and use it to see if user is in the org structure
		// DFCT0011800 - this is used to determine permissions, using GlideRecord Secure causes an ACL Loop
		var grOfficeOU = new GlideRecord("x_153465_discovert_discover_office_hierarchy");
		if(grOfficeOU.get(ouID)){
			// now get Top OU
			topOUId = grOfficeOU.getValue("u_top_ou");

			//Query organizational unit members to see if the user is a member
			// RAJ - STRY0011695 - change to use Glide Aggregate
			var grMembers = new GlideAggregate('x_153465_discovert_discover_office_members');
			grMembers.addEncodedQuery("discover_office_hierarchy.u_top_ou=" + topOUId + "^office_member=" + userID);
			// RAJ - STRY0011695 - change to use Glide Aggregate
			grMembers.addAggregate('COUNT');
			grMembers.query();

			if(grMembers.next()){
				// RAJ - STRY0011695 - change to use Glide Aggregate
				if (grMembers.getAggregate('COUNT') > 0){
					answer = true;
				}
			}
		}
		return answer;
	},


    type: 'task_privacy'
};
